package main

import (
	"fmt"
	"os"
	"text/template"

	"github.com/Masterminds/sprig/v3"
)

type Status struct {
	Added, Modified, Deleted, Unmerged, Untracked int
	Changed                                       bool
}

type Data struct {
	HEAD         string
	BranchStatus string
	Staging      Status
	Working      Status
}

func main() {
	tmpl := `[{{ .HEAD }}{{ if .BranchStatus }} {{ .BranchStatus }}{{ end }}{{ if .Staging.Changed }} +{{ .Staging.Added }} ~{{ .Staging.Modified }} -{{ .Staging.Deleted }}{{ if gt .Staging.Unmerged 0 }} !{{ .Staging.Unmerged }}{{ end }}{{ end }}{{ if and .Staging.Changed .Working.Changed }} |{{ end }}{{ if .Working.Changed }} +{{ add .Working.Added .Working.Untracked }} ~{{ .Working.Modified }} -{{ .Working.Deleted }}{{ if gt .Working.Unmerged 0 }} !{{ .Working.Unmerged }}{{ end }}{{ end }}{{ if .Working.Changed }} !{{ else if .Staging.Changed }} ~{{ end }}]`

	t := template.Must(template.New("t").Funcs(sprig.TxtFuncMap()).Parse(tmpl))

	d := Data{
		HEAD:         "main",
		BranchStatus: "↑2",
		Staging:      Status{Added: 2, Modified: 1, Deleted: 0, Changed: true},
		Working:      Status{Added: 0, Untracked: 1, Modified: 3, Deleted: 0, Changed: true},
	}
	t.Execute(os.Stdout, d)
	fmt.Println()
}
EOF
